// Some portions generated by Codex
package org.eclipse.rdf4j.sail.lmdb.benchmark;

import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.regex.Matcher;
import java.util.regex.Pattern;
import java.util.stream.Collectors;
import java.util.stream.Stream;

final class ThemeQueryHistory {

	private static final Pattern SUMMARY_ROW = Pattern.compile(
			"^ThemeQueryBenchmark\\.executeQuery\\s+([A-Z_]+)\\s+(\\d+)\\s+avgt\\s+(?:\\d+\\s+)?([0-9.]+)");
	private static final Pattern PARAMETERS = Pattern.compile(
			"^# Parameters: \\(themeName = ([A-Z_]+), z_queryIndex = (\\d+)\\)$",
			Pattern.MULTILINE);
	private static final Pattern QUERY_MARKER = Pattern.compile("^.*### (Optimized|Telemetry) Query ###\\s*$",
			Pattern.MULTILINE);
	private static final Pattern SPARQL_START = Pattern.compile("^(SELECT|ASK|CONSTRUCT|DESCRIBE)\\b");
	private static final Pattern SCORE_LINE = Pattern.compile(
			"^(?:Iteration\\s+\\d+:\\s+)?[0-9.]+(?:\\s+±\\s+[0-9.]+)?\\s+ms/op$");
	private static final Pattern RESULT_LINE = Pattern.compile("^Result \"");

	private ThemeQueryHistory() {
	}

	static Map<String, String> fastestPlanBearingOptimizedQueries(Path resultsDirectory) throws IOException {
		Map<String, BestQuery> bestQueries = new HashMap<>();
		try (Stream<Path> files = Files.list(resultsDirectory)) {
			for (Path file : files
					.filter(path -> path.getFileName().toString().startsWith("results-"))
					.filter(path -> path.getFileName().toString().endsWith(".md"))
					.sorted()
					.collect(Collectors.toList())) {
				parseResultFile(file, bestQueries);
			}
		}
		return bestQueries.entrySet()
				.stream()
				.collect(Collectors.toMap(Map.Entry::getKey, entry -> entry.getValue().optimizedQuery()));
	}

	private static void parseResultFile(Path file, Map<String, BestQuery> bestQueries) throws IOException {
		String text = Files.readString(file);
		Map<String, Double> scores = parseScores(text);
		List<Integer> parameterStarts = parameterStarts(text);

		Matcher matcher = PARAMETERS.matcher(text);
		for (int index = 0; matcher.find(); index++) {
			String key = matcher.group(1) + ":" + matcher.group(2);
			Double score = scores.get(key);
			if (score == null) {
				continue;
			}
			int end = index + 1 < parameterStarts.size() ? parameterStarts.get(index + 1) : text.length();
			QueryContent content = extractQueryContent(text.substring(matcher.start(), end));
			if (content.optimizedQuery() == null || !content.hasAnyPlan()) {
				continue;
			}
			BestQuery best = bestQueries.get(key);
			if (best == null || score < best.score()) {
				bestQueries.put(key, new BestQuery(score, content.optimizedQuery()));
			}
		}
	}

	private static List<Integer> parameterStarts(String text) {
		List<Integer> starts = new ArrayList<>();
		Matcher matcher = PARAMETERS.matcher(text);
		while (matcher.find()) {
			starts.add(matcher.start());
		}
		return starts;
	}

	private static Map<String, Double> parseScores(String text) {
		Map<String, Double> scores = new HashMap<>();
		for (String line : text.split("\\R")) {
			Matcher matcher = SUMMARY_ROW.matcher(line);
			if (matcher.find()) {
				scores.put(matcher.group(1) + ":" + matcher.group(2), Double.parseDouble(matcher.group(3)));
			}
		}
		return scores;
	}

	private static QueryContent extractQueryContent(String block) {
		Matcher matcher = QUERY_MARKER.matcher(block);
		String optimizedPlan = null;
		String optimizedQuery = null;
		String telemetryPlan = null;
		while (matcher.find()) {
			String kind = matcher.group(1);
			int sectionEnd = nextMarkerStart(block, matcher.end());
			Section section = extractMarkedQuerySection(block.substring(matcher.end(), sectionEnd));
			if ("Optimized".equals(kind)) {
				optimizedPlan = section.plan();
				optimizedQuery = section.query();
			} else {
				telemetryPlan = section.plan();
			}
		}
		return new QueryContent(optimizedPlan, optimizedQuery, telemetryPlan);
	}

	private static int nextMarkerStart(String block, int afterCurrent) {
		Matcher next = QUERY_MARKER.matcher(block);
		if (next.find(afterCurrent)) {
			return next.start();
		}
		return block.length();
	}

	private static Section extractMarkedQuerySection(String section) {
		List<String> lines = section.lines().collect(Collectors.toList());
		while (!lines.isEmpty() && lines.get(0).isBlank()) {
			lines.remove(0);
		}
		int queryStart = -1;
		for (int i = 0; i < lines.size(); i++) {
			if (SPARQL_START.matcher(lines.get(i)).find()) {
				queryStart = i;
				break;
			}
		}
		if (queryStart < 0) {
			return new Section(trimBlock(lines), null);
		}

		String plan = trimBlock(lines.subList(0, queryStart));
		List<String> query = lines.subList(queryStart, lines.size())
				.stream()
				.takeWhile(ThemeQueryHistory::isQueryLine)
				.collect(Collectors.toList());
		return new Section(plan, trimBlock(query));
	}

	private static boolean isQueryLine(String line) {
		String stripped = line.strip();
		return !RESULT_LINE.matcher(line).find()
				&& !SCORE_LINE.matcher(stripped).matches()
				&& !"# Run complete. Total time:".equals(stripped);
	}

	private static String trimBlock(List<String> lines) {
		int start = 0;
		int end = lines.size();
		while (start < end && lines.get(start).isBlank()) {
			start++;
		}
		while (end > start && lines.get(end - 1).isBlank()) {
			end--;
		}
		return start == end ? null : String.join("\n", lines.subList(start, end));
	}

	private record QueryContent(String optimizedPlan, String optimizedQuery, String telemetryPlan) {

		private boolean hasAnyPlan() {
			return optimizedPlan != null || telemetryPlan != null;
		}
	}

	private record Section(String plan, String query) {
	}

	private record BestQuery(double score, String optimizedQuery) {
	}
}
